SELECT AVG(cement) AS average_cement
FROM mix_designs
WHERE approved_by = 102;

SELECT mix_code, application_type 
FROM mix_designs 
WHERE mix_id = 1;

SELECT mv.version_id, mv.mix_id, mv.version_number, mv.changes, mv.created_at
FROM mix_versions mv
WHERE mv.mix_id IN (
  SELECT tr.mix_id 
  FROM test_results tr
  WHERE tr.compressive_strength > (
    SELECT AVG(compressive_strength) 
    FROM test_results
  )
);

SELECT COUNT(*) 
FROM materials 
WHERE material_id = 0;

SELECT MAX(compressive_strength) 
FROM mix_designs 
WHERE mix_id = 1;

SELECT DISTINCT mix_id
FROM quality_assurance
WHERE qa_result = 'fail';

SELECT project_name, project_id, budget
FROM projects
WHERE budget = (
  SELECT MAX(budget)
  FROM projects
);
